// ───────────────────────────────────────────────────────────────
// MODULE: Code Graph Query Handler
// ───────────────────────────────────────────────────────────────
// MCP tool handler for code_graph_query — queries structural relationships.

import * as graphDb from '../lib/code-graph-db.js';
import { ensureCodeGraphReady, type ReadyResult } from '../lib/ensure-ready.js';
import type { CodeNode, EdgeType } from '../lib/indexer-types.js';
import {
  attachGraphEdgeEnrichment,
  attachStructuralTrustFields,
  type EdgeEvidenceClass,
  type HotFileBreadcrumb,
} from '../lib/shared/shared-payload.js';
import {
  buildQueryTrustMetadata,
  buildReadinessBlock,
} from '../lib/readiness-contract.js';
import type {
  OutlineQueryNode,
  RelationshipQueryEdge,
} from '../lib/query-result-adapter.js';
import {
  traverseGraphBfs,
  type GraphBfsNeighbor,
  type GraphBfsPathStep,
} from '../lib/graph/bfs-traversal.js';
import {
  isCodeGraphBm25SymbolResolverEnabled,
  resolveSymbolBm25Candidates,
  type SymbolBm25Candidate,
} from '../lib/symbol-bm25-resolver.js';
// Emit a stable failure-counter metric so operators can distinguish DB /
// compute failures from legitimately empty blast radii.
import { isSpeckitMetricsEnabled, speckitMetrics } from '../lib/shared/metrics-stub.js';

export interface QueryArgs {
  operation: 'outline' | 'calls_from' | 'calls_to' | 'imports_from' | 'imports_to' | 'blast_radius';
  subject: string; // filePath, fqName, or symbolId
  subjects?: string[];
  edgeType?: string;
  limit?: number;
  includeTransitive?: boolean;
  maxDepth?: number;
  unionMode?: 'single' | 'multi';
  minConfidence?: number;
  includeTrace?: boolean;
  verificationGateBypass?: 'gold-query-verifier';
}

const SUPPORTED_EDGE_TYPES = [
  'CALLS',
  'CONTAINS',
  'DECORATES',
  'EXPORTS',
  'EXTENDS',
  'IMPLEMENTS',
  'IMPORTS',
  'OVERRIDES',
  'TESTED_BY',
  'TYPE_OF',
] as const satisfies readonly EdgeType[];

const SUPPORTED_EDGE_TYPE_SET = new Set<string>(SUPPORTED_EDGE_TYPES);
const AMBIGUOUS_SUBJECT_WARNING_CANDIDATE_LIMIT = 10;
const SYMBOL_BM25_SUGGESTION_LIMIT = 5;
const SUPPORTED_RELATIONSHIP_OPERATIONS = [
  'calls_from',
  'calls_to',
  'imports_from',
  'imports_to',
] as const;
const SUPPORTED_RELATIONSHIP_OPERATION_SET = new Set<string>(SUPPORTED_RELATIONSHIP_OPERATIONS);

/**
 * Regex used to decide whether a free-form `subject` argument looks like a
 * file path (so we should resolve it through `graphDb.resolveSubjectFilePath`)
 * versus a symbol name.
 *
 * Intentionally broader than `detectLanguage` in `lib/indexer-types.ts`: this
 * pattern recognises non-source assets the indexer does not parse but that
 * users still pass as subjects (e.g. `README.md`, `package.json`). Keep both
 * lists in sync at the language-coverage level only — extension drift between
 * the two lists is expected and documented here.
 */
const FILE_PATH_EXTENSION_PATTERN = /\.(?:[cm]?[jt]sx?|py|bash|zsh|sh|json|md)$/i;
const FILE_PATH_SEPARATOR_PATTERN = /[\\/]/;

function isSupportedEdgeType(edgeType: string): edgeType is EdgeType {
  return SUPPORTED_EDGE_TYPE_SET.has(edgeType);
}

function isSupportedRelationshipOperation(
  operation: string,
): operation is (typeof SUPPORTED_RELATIONSHIP_OPERATIONS)[number] {
  return SUPPORTED_RELATIONSHIP_OPERATION_SET.has(operation);
}

function buildUnknownOperationResponse(operation: string) {
  return {
    content: [{
      type: 'text' as const,
      text: JSON.stringify({ status: 'error', error: `Unknown operation: ${operation}` }),
    }],
  };
}

function resolveRequestedEdgeType(args: QueryArgs): { edgeType?: EdgeType; error?: string } {
  if (typeof args.edgeType === 'string' && args.edgeType.trim().length > 0) {
    const normalizedEdgeType = args.edgeType.trim().toUpperCase();
    // Reject typoed filters so empty results never masquerade as valid absence.
    if (!isSupportedEdgeType(normalizedEdgeType)) {
      return {
        error: `Unsupported edgeType "${args.edgeType}". Supported edge types: ${SUPPORTED_EDGE_TYPES.join(', ')}`,
      };
    }
    return { edgeType: normalizedEdgeType };
  }

  if (args.operation.startsWith('calls')) {
    return { edgeType: 'CALLS' };
  }

  if (args.operation.startsWith('imports')) {
    return { edgeType: 'IMPORTS' };
  }

  return {};
}

interface AmbiguousSubjectWarning {
  code: 'ambiguous_subject';
  subject: string;
  matchField: 'fq_name' | 'name' | 'symbol_id';
  count: number;
  candidates: SubjectCandidateMetadata[];
  selectedCandidate: SubjectCandidateMetadata;
  selectionReason: string;
  message: string;
}

interface ResolvedSubject {
  symbolId: string | null;
  selectedCandidate?: SubjectCandidateMetadata;
  warnings?: AmbiguousSubjectWarning[];
  suggestions?: SymbolBm25Candidate[];
}

interface SubjectCandidateMetadata {
  symbolId: string;
  fqName: string | null;
  name: string | null;
  kind: string | null;
  filePath: string | null;
  startLine: number | null;
  operationEdgeCount?: number;
  selectedForOperation?: QueryArgs['operation'];
}

interface SubjectMatchResult {
  candidates: SubjectCandidateMetadata[];
  count: number;
}

type BlastRadiusRiskLevel = 'low' | 'medium' | 'high';

interface BlastRadiusDependency {
  importedFilePath: string;
  importerFilePath: string;
  confidence: number;
}

interface WhyIncludedEdgeChainStep {
  fromFile: string;
  toFile: string;
  edgeType: 'IMPORTS';
  confidence: number;
}

interface BlastRadiusWhyIncluded {
  depth: number;
  edgeChain: WhyIncludedEdgeChainStep[];
  confidence: number;
  ambiguous: boolean;
  truncationReason: 'max_depth' | 'result_limit' | null;
}

interface BlastRadiusAffectedFile {
  filePath: string;
  depth: number;
  hotFileBreadcrumb?: HotFileBreadcrumb;
  why_included?: BlastRadiusWhyIncluded;
}

interface BlastRadiusFailureFallback {
  reason: string;
  /**
   * Stable machine-readable failure code so operators can distinguish
   * failure modes (DB error vs ambiguous subject vs unresolved
   * subject vs limit reached vs empty source) without parsing free-form
   * `reason` strings. Optional for backward compatibility with older
   * call sites.
   */
  code?: BlastRadiusFailureCode;
  partialResult?: {
    sourceFiles: string[];
    nodes: BlastRadiusAffectedFile[];
    affectedFiles: BlastRadiusAffectedFile[];
    depthGroups: Record<number, BlastRadiusAffectedFile[]>;
  };
}

/**
 * Stable failure-fallback code values surfaced via
 * `BlastRadiusFailureFallback.code`. Adding new values is non-breaking; do
 * not rename existing literals once consumers depend on them.
 */
type BlastRadiusFailureCode =
  | 'limit_reached'
  | 'unresolved_subject'
  | 'ambiguous_subject'
  | 'empty_source'
  | 'compute_error';

type FallbackDecision = {
  nextTool: 'code_graph_scan' | 'code_graph_query' | 'rg';
  reason: 'full_scan_required' | 'selective_reindex' | 'scan_failed' | 'scan_declined';
  retryAfter?: 'scan_complete';
};

function querySubjectMatches(
  field: 'fq_name' | 'name',
  subject: string,
): SubjectMatchResult {
  const d = graphDb.getDb();
  const candidates = d.prepare(`
    SELECT symbol_id, fq_name, name, kind, file_path, start_line
    FROM code_nodes
    WHERE ${field} = ?
    ORDER BY file_path, start_line, symbol_id
  `).all(subject) as Array<{
    symbol_id: string;
    fq_name: string | null;
    name: string | null;
    kind: string | null;
    file_path: string | null;
    start_line: number | null;
  }>;

  if (candidates.length === 0) {
    return { candidates: [], count: 0 };
  }

  return {
    candidates: candidates.map((candidate) => ({
      symbolId: candidate.symbol_id,
      fqName: candidate.fq_name,
      name: candidate.name,
      kind: candidate.kind,
      filePath: candidate.file_path,
      startLine: candidate.start_line,
    })),
    count: candidates.length,
  };
}

function relationshipEdgeCount(
  candidate: SubjectCandidateMetadata,
  operation: QueryArgs['operation'],
  edgeType: EdgeType | undefined,
): number {
  if (!candidate.symbolId) {
    return 0;
  }

  const resolvedEdgeType = edgeType ?? (
    operation.startsWith('calls')
      ? 'CALLS'
      : operation.startsWith('imports')
        ? 'IMPORTS'
        : undefined
  );

  if (!resolvedEdgeType) {
    return 0;
  }

  if (operation === 'calls_from' || operation === 'imports_from') {
    return graphDb.queryEdgesFrom(candidate.symbolId, resolvedEdgeType).length;
  }

  if (operation === 'calls_to' || operation === 'imports_to') {
    return graphDb.queryEdgesTo(candidate.symbolId, resolvedEdgeType).length;
  }

  return 0;
}

function callableKindRank(kind: string | null): number {
  switch (kind) {
    case 'function':
    case 'method':
      return 0;
    case 'class':
      return 1;
    case 'variable':
      return 2;
    default:
      return 3;
  }
}

function pickOperationAwareCandidate(
  candidates: SubjectCandidateMetadata[],
  operation: QueryArgs['operation'],
  edgeType: EdgeType | undefined,
): {
  selectedCandidate: SubjectCandidateMetadata;
  candidates: SubjectCandidateMetadata[];
  selectionReason: string;
} {
  const rankedCandidates = candidates
    .map((candidate) => ({
      ...candidate,
      operationEdgeCount: relationshipEdgeCount(candidate, operation, edgeType),
      selectedForOperation: operation,
    }))
    .sort((left, right) => (
      (right.operationEdgeCount ?? 0) - (left.operationEdgeCount ?? 0)
      || callableKindRank(left.kind) - callableKindRank(right.kind)
      || (left.filePath ?? '').localeCompare(right.filePath ?? '')
      || (left.startLine ?? Number.MAX_SAFE_INTEGER) - (right.startLine ?? Number.MAX_SAFE_INTEGER)
      || left.symbolId.localeCompare(right.symbolId)
    ));

  const selectedCandidate = rankedCandidates[0] ?? candidates[0];
  const highestEdgeCount = selectedCandidate?.operationEdgeCount ?? 0;
  const hasEdgeSignal = highestEdgeCount > 0;
  const selectionReason = hasEdgeSignal
    ? `${operation} edge count`
    : callableKindRank(selectedCandidate?.kind ?? null) === 0
      ? 'callable kind preference'
      : 'deterministic file ordering';

  return {
    selectedCandidate,
    candidates: rankedCandidates,
    selectionReason,
  };
}

function buildAmbiguousSubjectWarning(
  subject: string,
  matchField: 'fq_name' | 'name' | 'symbol_id',
  matchResult: SubjectMatchResult,
  selectedCandidate: SubjectCandidateMetadata,
  selectionReason: string,
): AmbiguousSubjectWarning {
  const truncated = matchResult.count > matchResult.candidates.length;
  const shownCount = matchResult.candidates.length;
  const countLabel = truncated
    ? `${matchResult.count} total; showing first ${shownCount}`
    : `${matchResult.count}`;

  return {
    code: 'ambiguous_subject',
    subject,
    matchField,
    count: matchResult.count,
    candidates: matchResult.candidates,
    selectedCandidate,
    selectionReason,
    message: `Multiple code graph nodes matched subject "${subject}" by ${matchField} (${countLabel}). Selected ${selectedCandidate.symbolId} for ${selectedCandidate.selectedForOperation ?? 'query'} using ${selectionReason}. Use a symbolId to disambiguate the query.`,
  };
}

function querySymbolBm25Suggestions(subject: string): SymbolBm25Candidate[] {
  if (!isCodeGraphBm25SymbolResolverEnabled()) {
    return [];
  }

  return resolveSymbolBm25Candidates(
    subject,
    graphDb.querySymbolIndexRows(),
    { limit: SYMBOL_BM25_SUGGESTION_LIMIT },
  );
}

function buildUnresolvedSubjectError(subject: string, suggestions: SymbolBm25Candidate[]) {
  const base = {
    status: 'error' as const,
    error: `Could not resolve subject: ${subject}`,
  };

  if (suggestions.length === 0) {
    return base;
  }

  return {
    ...base,
    data: {
      symbolResolution: {
        resolver: 'bm25',
        disambiguationOnly: true,
        message: 'No exact symbol match was found. These are candidate symbols only; use a symbolId, fqName, or exact name to run a structural query.',
        candidates: suggestions,
      },
    },
  };
}

/** Resolve a subject string to a symbolId */
function resolveSubject(
  subject: string,
  operation: QueryArgs['operation'],
  edgeType: EdgeType | undefined,
): ResolvedSubject {
  const d = graphDb.getDb();

  // Try as symbolId first
  const byId = d.prepare(`
    SELECT symbol_id, fq_name, name, kind, file_path, start_line
    FROM code_nodes
    WHERE symbol_id = ?
  `).get(subject) as {
    symbol_id: string;
    fq_name: string | null;
    name: string | null;
    kind: string | null;
    file_path: string | null;
    start_line: number | null;
  } | undefined;
  if (byId) {
    return {
      symbolId: byId.symbol_id,
      selectedCandidate: {
        symbolId: byId.symbol_id,
        fqName: byId.fq_name,
        name: byId.name,
        kind: byId.kind,
        filePath: byId.file_path,
        startLine: byId.start_line,
        selectedForOperation: operation,
      },
    };
  }

  // Try as fqName
  const byFq = querySubjectMatches('fq_name', subject);
  if (byFq.count > 0) {
    const selection = pickOperationAwareCandidate(byFq.candidates, operation, edgeType);
    return {
      symbolId: selection.selectedCandidate.symbolId,
      selectedCandidate: selection.selectedCandidate,
      ...(byFq.count > 1
        ? {
          warnings: [buildAmbiguousSubjectWarning(subject, 'fq_name', {
            ...byFq,
            candidates: selection.candidates.slice(0, AMBIGUOUS_SUBJECT_WARNING_CANDIDATE_LIMIT),
          }, selection.selectedCandidate, selection.selectionReason)]
        }
        : {}),
    };
  }

  // Try as name
  const byName = querySubjectMatches('name', subject);
  if (byName.count > 0) {
    const selection = pickOperationAwareCandidate(byName.candidates, operation, edgeType);
    return {
      symbolId: selection.selectedCandidate.symbolId,
      selectedCandidate: selection.selectedCandidate,
      ...(byName.count > 1
        ? {
          warnings: [buildAmbiguousSubjectWarning(subject, 'name', {
            ...byName,
            candidates: selection.candidates.slice(0, AMBIGUOUS_SUBJECT_WARNING_CANDIDATE_LIMIT),
          }, selection.selectedCandidate, selection.selectionReason)]
        }
        : {}),
    };
  }

  return { symbolId: null, suggestions: querySymbolBm25Suggestions(subject) };
}

// Readiness helpers extracted to lib/code-graph/readiness-contract.ts so the
// sibling code-graph handlers (scan, status, context) can share one
// vocabulary. See that module for durable mapping notes.

function buildGraphQueryPayload<T extends Record<string, unknown>>(
  payload: T,
  readiness: ReadyResult,
  label: string,
  graphEdgeEnrichment?: {
    edgeEvidenceClass: EdgeEvidenceClass;
    numericConfidence: number;
  } | null,
) {
  const { readiness: _incomingReadiness, ...rest } = payload as Record<string, unknown>;
  const { graphMetadata, structuralTrust } = buildQueryTrustMetadata(readiness);
  const fallbackDecision = Object.prototype.hasOwnProperty.call(rest, 'fallbackDecision')
    ? null
    : buildFallbackDecision(readiness);
  const payloadWithFallback = fallbackDecision
    ? { ...rest, fallbackDecision }
    : rest;
  const base = graphMetadata
    ? { ...payloadWithFallback, graphMetadata, readiness: buildReadinessBlock(readiness) }
    : { ...payloadWithFallback, readiness: buildReadinessBlock(readiness) };
  const withTrust = attachStructuralTrustFields(
    base as T & { readiness: ReturnType<typeof buildReadinessBlock> },
    structuralTrust,
    { label },
  );

  return graphEdgeEnrichment
    ? attachGraphEdgeEnrichment(withTrust, graphEdgeEnrichment, {
      label: `${label} graph edge enrichment`,
    })
    : withTrust;
}

type OutboundEdgeEntry = ReturnType<typeof graphDb.queryEdgesFrom>[number];
type InboundEdgeEntry = ReturnType<typeof graphDb.queryEdgesTo>[number];

interface DanglingEdgeWarning {
  code: 'dangling_edge';
  operation: QueryArgs['operation'];
  missingEndpoint: 'source' | 'target';
  count: number;
  danglingSymbolIds: string[];
  message: string;
}

type QueryWarning = AmbiguousSubjectWarning | DanglingEdgeWarning;

function mergeWarnings(...warningSets: Array<QueryWarning[] | undefined>): QueryWarning[] | undefined {
  const warnings = warningSets.flatMap((warningSet) => warningSet ?? []);
  return warnings.length > 0 ? warnings : undefined;
}

function excludeDanglingEdges<TEntry>(
  entries: TEntry[],
  limit: number,
  operation: QueryArgs['operation'],
  missingEndpoint: DanglingEdgeWarning['missingEndpoint'],
  isResolved: (entry: TEntry) => boolean,
  getDanglingId: (entry: TEntry) => string,
): { resolvedEntries: TEntry[]; warnings?: DanglingEdgeWarning[] } {
  const resolvedEntries: TEntry[] = [];
  const danglingSymbolIds: string[] = [];

  for (const entry of entries) {
    if (!isResolved(entry)) {
      danglingSymbolIds.push(getDanglingId(entry));
      continue;
    }
    if (resolvedEntries.length < limit) {
      resolvedEntries.push(entry);
    }
  }

  if (danglingSymbolIds.length === 0) {
    return { resolvedEntries };
  }

  return {
    resolvedEntries,
    warnings: [{
      code: 'dangling_edge',
      operation,
      missingEndpoint,
      count: danglingSymbolIds.length,
      danglingSymbolIds: [...new Set(danglingSymbolIds)],
      message: `Excluded ${danglingSymbolIds.length} dangling ${operation} edge(s) because the ${missingEndpoint} node could not be resolved. Reindex the code graph to repair the missing node references.`,
    }],
  };
}

/**
 * BFS transitive traversal from a symbolId via the given edge type.
 *
 * Dangling nodes (where queryEdgesFrom/To returns an edge whose endpoint has
 * no node row) were previously surfaced as
 * successful traversal results with null fqName/filePath. They are now
 * flagged as corruption alongside the resolved results so callers can
 * trust the absence of `warnings` as "no dangling references".
 */
interface TransitiveTraversalResult {
  nodes: Array<{
    symbolId: string;
    fqName: string | null;
    filePath: string | null;
    line: number | null;
    depth: number;
  }>;
  warnings?: DanglingEdgeWarning[];
}

interface TransitiveTraversalNeighbor {
  readonly symbolId: string;
  readonly node: CodeNode | null;
}

function transitiveTraversal(
  startId: string,
  edgeType: string,
  direction: 'from' | 'to',
  maxDepth: number,
  limit: number,
  operation: QueryArgs['operation'],
): TransitiveTraversalResult {
  const resultSymbolIds = new Set<string>();
  const missingEndpoint: DanglingEdgeWarning['missingEndpoint'] = direction === 'from' ? 'target' : 'source';
  const traversal = traverseGraphBfs<string, TransitiveTraversalNeighbor, TransitiveTraversalResult['nodes'][number]>({
    startIds: [startId],
    maxDepth,
    resultLimit: limit,
    visitTiming: 'dequeue',
    stopEnqueueWhenResultLimitReached: true,
    getNeighbors: (item) => {
      if (direction === 'from') {
        return graphDb.queryEdgesFrom(item.id, edgeType).map<GraphBfsNeighbor<string, TransitiveTraversalNeighbor>>(({ edge, targetNode }) => ({
          id: edge.targetId,
          payload: { symbolId: edge.targetId, node: targetNode },
          ...(targetNode == null ? { danglingId: edge.targetId } : {}),
        }));
      }

      return graphDb.queryEdgesTo(item.id, edgeType).map<GraphBfsNeighbor<string, TransitiveTraversalNeighbor>>(({ edge, sourceNode }) => ({
        id: edge.sourceId,
        payload: { symbolId: edge.sourceId, node: sourceNode },
        ...(sourceNode == null ? { danglingId: edge.sourceId } : {}),
      }));
    },
    mapResult: (visit) => {
      if (resultSymbolIds.has(visit.payload.symbolId) || visit.payload.node == null) {
        return null;
      }
      resultSymbolIds.add(visit.payload.symbolId);
      return {
        symbolId: visit.payload.symbolId,
        fqName: visit.payload.node.fqName ?? null,
        filePath: visit.payload.node.filePath ?? null,
        line: visit.payload.node.startLine ?? null,
        depth: visit.depth,
      };
    },
  });

  const nodes = traversal.results.map((entry) => entry.value).slice(0, limit);
  if (traversal.dangling.length === 0) {
    return { nodes };
  }

  const uniqueDangling = [...new Set(traversal.dangling.map((entry) => entry.id))];
  return {
    nodes,
    warnings: [{
      code: 'dangling_edge',
      operation,
      missingEndpoint,
      count: uniqueDangling.length,
      danglingSymbolIds: uniqueDangling,
      message: `Transitive ${operation} traversal encountered ${uniqueDangling.length} dangling ${missingEndpoint} node reference(s). Reindex the code graph to repair the missing node references.`,
    }],
  };
}

function classifyEdgeEvidenceClass(
  edgeType: string,
  metadata: Record<string, unknown> | undefined,
): EdgeEvidenceClass {
  switch (edgeType) {
    case 'IMPORTS':
    case 'EXPORTS':
      return 'import';
    case 'EXTENDS':
    case 'IMPLEMENTS':
    case 'TYPE_OF':
      return 'type_reference';
    case 'TESTED_BY':
      return 'test_coverage';
    default:
      return metadata?.detectorProvenance === 'heuristic' || metadata?.evidenceClass === 'INFERRED'
        ? 'inferred_heuristic'
        : 'direct_call';
  }
}

function clampNumericConfidence(value: unknown): number {
  if (typeof value !== 'number' || !Number.isFinite(value)) {
    return 0;
  }
  return Math.max(0, Math.min(1, value));
}

function edgeMetadataOutput(edge: OutboundEdgeEntry['edge'] | InboundEdgeEntry['edge']) {
  return {
    confidence: clampNumericConfidence(edge.metadata?.confidence ?? edge.weight),
    numericConfidence: clampNumericConfidence(edge.metadata?.confidence ?? edge.weight),
    detectorProvenance: edge.metadata?.detectorProvenance ?? null,
    evidenceClass: edge.metadata?.evidenceClass ?? null,
    reason: graphDb.sanitizeEdgeMetadataString(edge.metadata?.reason),
    step: graphDb.sanitizeEdgeMetadataString(edge.metadata?.step),
    edgeEvidenceClass: classifyEdgeEvidenceClass(
      edge.edgeType,
      edge.metadata as Record<string, unknown> | undefined,
    ),
  };
}

/* ───────────────────────────────────────────────────────────────
   Shared relationship-edge mapper
   --------------------------------------------------------------
   Replaces near-duplicate switch branches for `calls_from`,
   `calls_to`, `imports_from`, and `imports_to`. Two inputs control
   the variant: (1) direction = outbound (target side) vs inbound
   (source side); (2) whether to surface the start line.
─────────────────────────────────────────────────────────────── */

type RelationshipMappedEdge = RelationshipQueryEdge & {
  confidence: number;
  numericConfidence: number;
  detectorProvenance: string | null;
  evidenceClass: string | null;
  reason: string | null;
  step: string | null;
  edgeEvidenceClass: EdgeEvidenceClass;
};

function mapOutboundRelationshipEdge(
  entry: OutboundEdgeEntry,
  options: { includeLine: boolean },
): RelationshipMappedEdge {
  return {
    target: entry.targetNode?.fqName ?? entry.edge.targetId,
    file: entry.targetNode?.filePath,
    ...(options.includeLine ? { line: entry.targetNode?.startLine } : {}),
    ...edgeMetadataOutput(entry.edge),
  };
}

function mapInboundRelationshipEdge(
  entry: InboundEdgeEntry,
  options: { includeLine: boolean },
): RelationshipMappedEdge {
  return {
    source: entry.sourceNode?.fqName ?? entry.edge.sourceId,
    file: entry.sourceNode?.filePath,
    ...(options.includeLine ? { line: entry.sourceNode?.startLine } : {}),
    ...edgeMetadataOutput(entry.edge),
  };
}

function extractOutboundFilePaths(entries: OutboundEdgeEntry[]): string[] {
  return entries
    .map((entry) => entry.targetNode?.filePath)
    .filter((value): value is string => typeof value === 'string');
}

function extractInboundFilePaths(entries: InboundEdgeEntry[]): string[] {
  return entries
    .map((entry) => entry.sourceNode?.filePath)
    .filter((value): value is string => typeof value === 'string');
}

function subjectLooksLikeFilePath(subject: string): boolean {
  return FILE_PATH_SEPARATOR_PATTERN.test(subject) || FILE_PATH_EXTENSION_PATTERN.test(subject);
}

function resolveRelationshipFilePath(subject: string): string | null {
  if (!subjectLooksLikeFilePath(subject)) {
    return null;
  }

  const resolvedFilePath = graphDb.resolveSubjectFilePath(subject);
  return typeof resolvedFilePath === 'string' && resolvedFilePath.length > 0
    ? resolvedFilePath
    : null;
}

function queryRelationshipFileSymbols(filePath: string): CodeNode[] {
  return graphDb
    .queryOutline(filePath)
    .filter((node) => typeof node.symbolId === 'string' && node.symbolId.length > 0);
}

function relationshipFilePayload(input: {
  operation: QueryArgs['operation'];
  filePath: string;
  symbols: CodeNode[];
  edgeType: EdgeType | undefined;
  limit: number;
}): {
  result: {
    operation: QueryArgs['operation'];
    filePath: string;
    subjectKind: 'file_path';
    symbolCount: number;
    edgeType: EdgeType | undefined;
    edges: RelationshipMappedEdge[];
    warnings?: DanglingEdgeWarning[];
    hotFileBreadcrumbs: ReturnType<typeof buildHotFileBreadcrumbs>;
  };
  edgeEnrichment: ReturnType<typeof summarizeWeakestGraphEdgeEnrichment>;
} {
  const sourceIds = input.symbols.map((node) => node.symbolId);
  if (input.operation === 'calls_from' || input.operation === 'imports_from') {
    const entries = sourceIds.flatMap((symbolId) => graphDb.queryEdgesFrom(symbolId, input.edgeType));
    const { resolvedEntries, warnings } = excludeDanglingEdges(
      entries,
      input.limit,
      input.operation,
      'target',
      (entry: OutboundEdgeEntry) => entry.targetNode != null,
      (entry: OutboundEdgeEntry) => entry.edge.targetId,
    );
    const includeLine = input.operation === 'calls_from';
    const edges = resolvedEntries.map((entry) => mapOutboundRelationshipEdge(entry, { includeLine }));
    return {
      result: {
        operation: input.operation,
        filePath: input.filePath,
        subjectKind: 'file_path',
        symbolCount: input.symbols.length,
        edgeType: input.edgeType,
        edges,
        ...(warnings ? { warnings } : {}),
        hotFileBreadcrumbs: buildHotFileBreadcrumbs(extractOutboundFilePaths(resolvedEntries)),
      },
      edgeEnrichment: summarizeWeakestGraphEdgeEnrichment(edges),
    };
  }

  const entries = sourceIds.flatMap((symbolId) => graphDb.queryEdgesTo(symbolId, input.edgeType));
  const { resolvedEntries, warnings } = excludeDanglingEdges(
    entries,
    input.limit,
    input.operation,
    'source',
    (entry: InboundEdgeEntry) => entry.sourceNode != null,
    (entry: InboundEdgeEntry) => entry.edge.sourceId,
  );
  const includeLine = input.operation === 'calls_to';
  const edges = resolvedEntries.map((entry) => mapInboundRelationshipEdge(entry, { includeLine }));
  return {
    result: {
      operation: input.operation,
      filePath: input.filePath,
      subjectKind: 'file_path',
      symbolCount: input.symbols.length,
      edgeType: input.edgeType,
      edges,
      ...(warnings ? { warnings } : {}),
      hotFileBreadcrumbs: buildHotFileBreadcrumbs(extractInboundFilePaths(resolvedEntries)),
    },
    edgeEnrichment: summarizeWeakestGraphEdgeEnrichment(edges),
  };
}

const EDGE_EVIDENCE_CLASS_WEAKNESS: Record<EdgeEvidenceClass, number> = {
  inferred_heuristic: 0,
  test_coverage: 1,
  type_reference: 2,
  import: 3,
  direct_call: 4,
};

function summarizeWeakestGraphEdgeEnrichment(
  edges: Array<{
    edgeEvidenceClass: EdgeEvidenceClass;
    numericConfidence: number;
  }>,
): {
  edgeEvidenceClass: EdgeEvidenceClass;
  numericConfidence: number;
} | null {
  let weakest: {
    edgeEvidenceClass: EdgeEvidenceClass;
    numericConfidence: number;
  } | null = null;

  for (const edge of edges) {
    if (weakest == null || edge.numericConfidence < weakest.numericConfidence) {
      weakest = edge;
      continue;
    }

    if (
      edge.numericConfidence === weakest.numericConfidence
      && EDGE_EVIDENCE_CLASS_WEAKNESS[edge.edgeEvidenceClass]
      < EDGE_EVIDENCE_CLASS_WEAKNESS[weakest.edgeEvidenceClass]
    ) {
      weakest = edge;
    }
  }

  return weakest;
}

function shouldBlockReadPath(readiness: ReadyResult, verificationGateBypassed = false): boolean {
  // False-safe contract: answer ONLY on a fresh graph. Any
  // non-fresh state must block rather than return a possibly-wrong structural
  // answer with status:'ok'. The previous predicate keyed only on
  // `action === 'full_scan' && !inlineIndexPerformed`, which let two non-fresh
  // states slip through: (a) a deleted-files-only `freshness:'stale', action:'none'`
  // result, and (b) a FAILED inline selective_reindex (`freshness:'stale',
  // inlineIndexPerformed:false`). Both returned ok over a stale graph. We now
  // gate on freshness directly and also refuse a failed gold-verification gate,
  // matching `detect_changes` readinessRequiresBlock for a single contract.
  return readiness.freshness !== 'fresh'
    || (!verificationGateBypassed && readiness.verificationGate === 'fail');
}

function buildFallbackDecision(readiness: ReadyResult): FallbackDecision | null {
  if (readiness.freshness === 'error') {
    return {
      nextTool: 'rg',
      reason: 'scan_failed',
    };
  }

  // Any non-fresh graph that reached the block path needs a scan before reads
  // can be trusted (full_scan, empty, or a stale graph a selective reindex
  // could not heal).
  if (readiness.freshness !== 'fresh') {
    return {
      nextTool: 'code_graph_scan',
      reason: readiness.action === 'selective_reindex' ? 'selective_reindex' : 'full_scan_required',
      retryAfter: 'scan_complete',
    };
  }

  return null;
}

function buildBlockedReadPayload(
  readiness: ReadyResult,
  operation: QueryArgs['operation'],
  subject: string,
) {
  const fallbackDecision = buildFallbackDecision(readiness);
  // Surface scope + manifest diagnostics directly on the
  // blocked payload's `data` object so operators can route on
  // them without parsing `data.readiness`. Backward compatible:
  // legacy callers reading `status` + `data.blockReason` continue
  // to work; nested `data.readiness` still carries the same fields.
  return {
    status: 'blocked',
    message: `code_graph_full_scan_required: ${readiness.reason}`,
    data: buildGraphQueryPayload({
      operation,
      subject,
      blocked: true,
      degraded: true,
      graphAnswersOmitted: true,
      requiredAction: 'code_graph_scan',
      blockReason: 'full_scan_required',
      reason: readiness.reason,
      activeScope: readiness.activeScope ?? null,
      storedScope: readiness.storedScope ?? null,
      manifestCount: readiness.manifestCount ?? null,
      manifestDigest: readiness.manifestDigest ?? null,
      ...(fallbackDecision ? { fallbackDecision } : {}),
    }, readiness, `code_graph_query ${operation} blocked payload`),
  };
}

function buildHotFileBreadcrumbs(filePaths: string[]): Array<{
  filePath: string;
  hotFileBreadcrumb: HotFileBreadcrumb;
}> {
  const uniqueFilePaths = [...new Set(filePaths)];
  if (uniqueFilePaths.length === 0) {
    return [];
  }

  const degreeRows = graphDb.queryFileDegrees(uniqueFilePaths);
  const positiveDegrees = degreeRows
    .map((row) => row.degree)
    .filter((degree) => degree > 0)
    .sort((left, right) => right - left);
  if (positiveDegrees.length === 0) {
    return [];
  }

  const topCount = Math.max(1, Math.ceil(positiveDegrees.length * 0.1));
  const threshold = Math.min(20, positiveDegrees[topCount - 1] ?? positiveDegrees[0]);

  return degreeRows
    .filter((row) => row.degree >= threshold)
    .map((row) => ({
      filePath: row.filePath,
      hotFileBreadcrumb: {
        degree: row.degree,
        changeCarefullyReason: `High-degree node; change carefully because changes here ripple to ${row.degree} dependents.`,
      },
    }));
}

function parseEdgeMetadataConfidence(metadataJson: unknown, weight: unknown): number {
  if (typeof metadataJson === 'string' && metadataJson.length > 0) {
    try {
      const metadata = JSON.parse(metadataJson) as Record<string, unknown>;
      return clampNumericConfidence(metadata.confidence ?? weight);
    } catch {
      return clampNumericConfidence(weight);
    }
  }
  return clampNumericConfidence(weight);
}

function queryImportDependentsForBlastRadius(minConfidence: number, includeTrace = false): BlastRadiusDependency[] {
  if (minConfidence <= 0 && !includeTrace) {
    return graphDb.queryFileImportDependents().map((edge) => ({
      ...edge,
      confidence: 1,
    }));
  }

  const d = graphDb.getDb();
  const rows = d.prepare(`
    SELECT
      target.file_path AS imported_file_path,
      source.file_path AS importer_file_path,
      edge.weight AS weight,
      edge.metadata AS metadata
    FROM code_edges edge
    INNER JOIN code_nodes source ON source.symbol_id = edge.source_id
    INNER JOIN code_nodes target ON target.symbol_id = edge.target_id
    WHERE UPPER(edge.edge_type) = 'IMPORTS'
      AND source.file_path != target.file_path
  `).all() as Array<{
    imported_file_path: string;
    importer_file_path: string;
    weight: number | null;
    metadata: string | null;
  }>;

  return rows
    .map((row) => ({
      importedFilePath: row.imported_file_path,
      importerFilePath: row.importer_file_path,
      confidence: parseEdgeMetadataConfidence(row.metadata, row.weight ?? 1),
    }))
    .filter((edge) => edge.confidence >= minConfidence);
}

function buildDepthGroups(
  affectedFiles: BlastRadiusAffectedFile[],
  maxDepth: number,
): Record<number, BlastRadiusAffectedFile[]> {
  const depthGroups: Record<number, BlastRadiusAffectedFile[]> = {};
  for (let depth = 1; depth <= Math.max(0, maxDepth); depth++) {
    depthGroups[depth] = [];
  }
  for (const affectedFile of affectedFiles) {
    depthGroups[affectedFile.depth] ??= [];
    depthGroups[affectedFile.depth].push(affectedFile);
  }
  return depthGroups;
}

/**
 * Classify a blast-radius response by depth-one fanout.
 *
 * Thresholds (008/D9 — documented):
 *   - **high**: any of (a) ambiguityCandidates non-empty, (b) depth-one fanout > 10
 *   - **medium**: depth-one fanout in [4, 10]
 *   - **low**: depth-one fanout in [0, 3]
 *
 * Depth-one is used (not max depth) because the immediate consumers of
 * the seed are the strongest blast-radius signal in practice.
 */
function classifyBlastRadiusRisk(
  depthGroups: Record<number, BlastRadiusAffectedFile[]>,
  ambiguityCandidates: SubjectCandidateMetadata[],
): BlastRadiusRiskLevel {
  const depthOneCount = depthGroups[1]?.length ?? 0;
  if (ambiguityCandidates.length > 0 || depthOneCount > 10) {
    return 'high';
  }
  if (depthOneCount >= 4) {
    return 'medium';
  }
  return 'low';
}

function buildPartialBlastRadiusResult(
  sourceFiles: string[],
  nodes: BlastRadiusAffectedFile[],
  affectedFiles: BlastRadiusAffectedFile[],
  depthGroups: Record<number, BlastRadiusAffectedFile[]>,
): NonNullable<BlastRadiusFailureFallback['partialResult']> {
  return {
    sourceFiles,
    nodes,
    affectedFiles,
    depthGroups,
  };
}

function computeBlastRadius(
  sourceFiles: string[],
  maxDepth: number,
  limit: number,
  minConfidence = 0,
  ambiguityCandidates: SubjectCandidateMetadata[] = [],
  includeTrace = false,
) {
  const importedBy = new Map<string, BlastRadiusDependency[]>();
  const importEdges = queryImportDependentsForBlastRadius(minConfidence, includeTrace);
  for (const edge of importEdges) {
    const importers = importedBy.get(edge.importedFilePath) ?? [];
    if (!importers.some((existing) => existing.importerFilePath === edge.importerFilePath)) {
      importers.push(edge);
    }
    importedBy.set(edge.importedFilePath, importers);
  }

  const affectedByFile = new Map<string, { depth: number; why_included?: BlastRadiusWhyIncluded }>();
  const normalizedSources = [...new Set(sourceFiles)];
  let depthTruncated = false;
  let overflowed = false;

  const buildWhyIncluded = (
    depth: number,
    path: ReadonlyArray<GraphBfsPathStep<string, BlastRadiusDependency>>,
    truncationReason: BlastRadiusWhyIncluded['truncationReason'],
  ): BlastRadiusWhyIncluded => {
    const edgeChain = path.map((step) => ({
      fromFile: step.payload.importedFilePath,
      toFile: step.payload.importerFilePath,
      edgeType: 'IMPORTS' as const,
      confidence: step.payload.confidence,
    }));
    // Neutral seed for a min-reduce over confidences clamped to [0,1]; an
    // empty chain yields 1 (no edge constrains the confidence).
    const confidence = edgeChain.reduce(
      (minimum, step) => Math.min(minimum, step.confidence),
      1,
    );
    return {
      depth,
      edgeChain,
      confidence,
      ambiguous: ambiguityCandidates.length > 0,
      truncationReason,
    };
  };

  for (const sourceFile of normalizedSources) {
    const traversal = traverseGraphBfs<string, BlastRadiusDependency, BlastRadiusAffectedFile>({
      startIds: [sourceFile],
      maxDepth,
      preVisitedIds: [sourceFile],
      visitTiming: 'enqueue',
      inspectDepthBoundary: true,
      getNeighbors: (item) => [...(importedBy.get(item.id) ?? [])]
        .sort((left, right) => left.importerFilePath.localeCompare(right.importerFilePath))
        .map((edge) => ({
          id: edge.importerFilePath,
          payload: edge,
        })),
      mapResult: (visit) => normalizedSources.includes(visit.id)
        ? null
        : {
          filePath: visit.id,
          depth: visit.depth,
          ...(includeTrace
            ? { why_included: buildWhyIncluded(visit.depth, visit.path, null) }
            : {}),
        },
    });

    depthTruncated ||= traversal.depthTruncated;
    const maxDepthTruncatedFrom = new Set(traversal.truncated.map((entry) => entry.fromId));
    for (const affectedFile of traversal.results.map((entry) => entry.value)) {
      if (includeTrace && affectedFile.why_included && maxDepthTruncatedFrom.has(affectedFile.filePath)) {
        affectedFile.why_included = {
          ...affectedFile.why_included,
          truncationReason: 'max_depth',
        };
      }
      const previous = affectedByFile.get(affectedFile.filePath);
      if (previous === undefined || affectedFile.depth < previous.depth) {
        affectedByFile.set(affectedFile.filePath, {
          depth: affectedFile.depth,
          ...(affectedFile.why_included ? { why_included: affectedFile.why_included } : {}),
        });
      }
    }
  }

  // Detect true overflow by comparing the full traversal size against `limit`
  // BEFORE slicing. Previously `affectedFiles.length >= limit`
  // false-positived whenever the reachable set happened to equal `limit`
  // exactly. We over-collect (`limit + 1` semantically — here the whole
  // BFS frontier is already in `affectedByFile`) and slice down only after
  // recording overflow.
  const totalAffectedBeforeSlice = affectedByFile.size;
  let affectedFiles = [...affectedByFile.entries()]
    .map(([filePath, entry]) => ({
      filePath,
      depth: entry.depth,
      ...(entry.why_included ? { why_included: entry.why_included } : {}),
    }))
    .sort((left, right) => left.depth - right.depth || left.filePath.localeCompare(right.filePath))
    .slice(0, limit);
  overflowed = totalAffectedBeforeSlice > limit;
  if (includeTrace && overflowed && affectedFiles.length > 0) {
    const lastIncluded = affectedFiles[affectedFiles.length - 1];
    if (lastIncluded.why_included && lastIncluded.why_included.truncationReason == null) {
      lastIncluded.why_included = {
        ...lastIncluded.why_included,
        truncationReason: 'result_limit',
      };
    }
  }
  const breadcrumbByFile = new Map(
    buildHotFileBreadcrumbs([
      ...normalizedSources,
      ...affectedFiles.map((entry) => entry.filePath),
    ]).map((entry) => [entry.filePath, entry.hotFileBreadcrumb]),
  );
  affectedFiles = affectedFiles.map((entry) => ({
    ...entry,
    ...(breadcrumbByFile.get(entry.filePath) ? { hotFileBreadcrumb: breadcrumbByFile.get(entry.filePath) } : {}),
  }));

  const seedNodes = normalizedSources.map((filePath) => ({
    filePath,
    depth: 0,
    isSeed: true,
    ...(includeTrace
      ? {
        why_included: buildWhyIncluded(0, [], null),
      }
      : {}),
    ...(breadcrumbByFile.get(filePath) ? { hotFileBreadcrumb: breadcrumbByFile.get(filePath) } : {}),
  }));
  const depthGroups = buildDepthGroups(affectedFiles, maxDepth);

  return {
    sourceFiles: normalizedSources,
    nodes: [
      ...seedNodes,
      ...affectedFiles,
    ],
    affectedFiles,
    depthGroups,
    riskLevel: classifyBlastRadiusRisk(depthGroups, ambiguityCandidates),
    minConfidence,
    ambiguityCandidates,
    hotFileBreadcrumbs: [...breadcrumbByFile.entries()].map(([filePath, hotFileBreadcrumb]) => ({
      filePath,
      hotFileBreadcrumb,
    })),
    // Omitted when the traversal reached the full depth horizon, mirroring the
    // `overflowed`-driven conditional spread below so the field is absent
    // (rather than `false`) in the common, complete case.
    ...(depthTruncated ? { depthTruncated: true } : {}),
    ...(overflowed
      ? {
        failureFallback: {
          reason: 'limit_reached',
          code: 'limit_reached',
          partialResult: buildPartialBlastRadiusResult(
            normalizedSources,
            [...seedNodes, ...affectedFiles],
            affectedFiles,
            depthGroups,
          ),
        } satisfies BlastRadiusFailureFallback,
      }
      : {}),
  };
}

/** Handle code_graph_query tool call */
export async function handleCodeGraphQuery(args: QueryArgs): Promise<{ content: Array<{ type: string; text: string }> }> {
  let readiness: ReadyResult = {
    freshness: 'empty' as const,
    action: 'none' as const,
    inlineIndexPerformed: false,
    reason: 'readiness check not run',
  };

  // Auto-trigger: ensure graph is fresh before querying
  try {
    readiness = await ensureCodeGraphReady(process.cwd(), {
      allowInlineIndex: true,
      allowInlineFullScan: false,
      allowGuardedInlineFullScan: true,
    });
  } catch (error) {
    // Emit 'unavailable' trust-state on readiness-crash so query consumers
    // see the same canonical vocabulary
    // as code_graph_context. Previously this path dropped the readiness
    // block entirely and only returned a status:'error' string.
    const reason = error instanceof Error ? error.message : String(error);
    const crashReadiness: ReadyResult = {
      freshness: 'error' as const,
      action: 'none' as const,
      inlineIndexPerformed: false,
      reason: 'readiness_check_crashed',
    };
    const crashBlock = buildReadinessBlock(crashReadiness);
    return {
      content: [{
        type: 'text',
        text: JSON.stringify({
          // Align with code_graph_context + detect_changes — a non-fresh
          // / unavailable graph (here: readiness probe crashed) refuses with
          // status:'blocked', not 'error', so all three read handlers share one
          // refusal token. The structured readiness block + rg fallback are
          // preserved so consumers still see the crash detail.
          status: 'blocked',
          message: `code_graph_not_ready: ${reason}`,
          data: {
            readiness: crashBlock,
            canonicalReadiness: crashBlock.canonicalReadiness,
            trustState: crashBlock.trustState,
            fallbackDecision: buildFallbackDecision(crashReadiness),
          },
        }),
      }],
    };
  }

  const { operation, subject } = args;
  const limit = Math.max(1, Math.min(Number(args.limit) || 50, 1000));
  const { edgeType: requestedEdgeType, error: edgeTypeError } = resolveRequestedEdgeType(args);
  const rawMaxDepth = args.maxDepth === undefined ? 3 : Number(args.maxDepth);
  const maxDepth = Math.max(0, Math.min(Number.isFinite(rawMaxDepth) ? rawMaxDepth : 3, 20));

  if (edgeTypeError) {
    return {
      content: [{
        type: 'text',
        text: JSON.stringify({ status: 'error', error: edgeTypeError }),
      }],
    };
  }

  if (shouldBlockReadPath(readiness, args.verificationGateBypass === 'gold-query-verifier')) {
    return {
      content: [{
        type: 'text',
        text: JSON.stringify(buildBlockedReadPayload(readiness, operation, subject), null, 2),
      }],
    };
  }

  if (operation === 'outline') {
    const resolvedSubject = graphDb.resolveSubjectFilePath(subject);
    if (typeof resolvedSubject !== 'string' || resolvedSubject.length === 0) {
      return {
        content: [{
          type: 'text',
          text: JSON.stringify({
            status: 'error',
            error: `Could not resolve outline subject: ${subject}`,
          }),
        }],
      };
    }

    const nodes = graphDb.queryOutline(resolvedSubject);
    const limited = nodes.slice(0, limit);
    const outlineNodes: OutlineQueryNode[] = limited.map(n => ({
      name: n.name,
      kind: n.kind,
      fqName: n.fqName,
      line: n.startLine,
      signature: n.signature,
      symbolId: n.symbolId,
    }));
    return {
      content: [{
        type: 'text',
        text: JSON.stringify({
          status: 'ok',
          data: buildGraphQueryPayload({
            operation: 'outline',
            filePath: resolvedSubject,
            nodeCount: outlineNodes.length,
            nodes: outlineNodes,
          }, readiness, 'code_graph_query outline payload'),
        }, null, 2),
      }],
    };
  }

  if (operation === 'blast_radius') {
    // Honor the documented `includeTransitive` flag for blast_radius: the schema
    // describes it as "Enable multi-hop BFS traversal" (default false) with
    // `maxDepth` applying only when it is true. Default returns direct importers
    // only (depth 1); the flag opts into multi-hop closure up to maxDepth. (The
    // call-graph operations gate on the same flag in their own branch.)
    const effectiveDepth = args.includeTransitive ? maxDepth : 1;
    const rawSubjects = args.unionMode === 'multi'
      ? [subject, ...(args.subjects ?? [])]
      : [subject];
    const sourceFiles: string[] = [];
    const ambiguityCandidates: SubjectCandidateMetadata[] = [];
    const minConfidence = clampNumericConfidence(args.minConfidence ?? 0);

    for (const candidate of rawSubjects) {
      const candidateLooksLikeFilePath = subjectLooksLikeFilePath(candidate);
      let resolvedPathCandidate: string | null = null;
      if (candidateLooksLikeFilePath) {
        const resolvedFileCandidate = graphDb.resolveSubjectFilePath(candidate);
        if (typeof resolvedFileCandidate === 'string' && resolvedFileCandidate.length > 0) {
          sourceFiles.push(resolvedFileCandidate);
          continue;
        }
        resolvedPathCandidate = resolvedFileCandidate;
      }

      const byFqName = querySubjectMatches('fq_name', candidate);
      if (byFqName.count > 1) {
        ambiguityCandidates.push(...byFqName.candidates.slice(0, AMBIGUOUS_SUBJECT_WARNING_CANDIDATE_LIMIT));
        continue;
      }
      if (byFqName.count === 0) {
        const byName = querySubjectMatches('name', candidate);
        if (byName.count > 1) {
          ambiguityCandidates.push(...byName.candidates.slice(0, AMBIGUOUS_SUBJECT_WARNING_CANDIDATE_LIMIT));
          continue;
        }
      }

      const resolvedSubject = resolvedPathCandidate ?? graphDb.resolveSubjectFilePath(candidate);
      if (typeof resolvedSubject !== 'string' || resolvedSubject.length === 0) {
        // Preserve any sibling seeds we have already resolved ahead of this
        // failed candidate. Returning `nodes: []` here would
        // discard work the caller can still use; instead surface the
        // already-resolved seeds so multi-subject blast-radius queries
        // degrade gracefully when one subject fails to resolve.
        const preservedDepthGroups = buildDepthGroups([], effectiveDepth);
        const preservedSeedNodes = sourceFiles.map((filePath) => ({
          filePath,
          depth: 0,
          isSeed: true,
        }));
        return {
          content: [{
            type: 'text',
            text: JSON.stringify({
              status: 'ok',
              data: buildGraphQueryPayload({
                operation,
                sourceFiles,
                nodes: preservedSeedNodes,
                affectedFiles: [],
                depthGroups: preservedDepthGroups,
                riskLevel: classifyBlastRadiusRisk(preservedDepthGroups, []),
                minConfidence,
                ambiguityCandidates: [],
                failureFallback: {
                  reason: `unresolved_subject: ${candidate}`,
                  code: 'unresolved_subject',
                  partialResult: buildPartialBlastRadiusResult(
                    sourceFiles,
                    preservedSeedNodes,
                    [],
                    preservedDepthGroups,
                  ),
                } satisfies BlastRadiusFailureFallback,
              }, readiness, 'code_graph_query blast_radius fallback payload'),
            }, null, 2),
          }],
        };
      }
      sourceFiles.push(resolvedSubject);
    }

    if (ambiguityCandidates.length > 0) {
      const depthGroups = buildDepthGroups([], effectiveDepth);
      return {
        content: [{
          type: 'text',
          text: JSON.stringify({
            status: 'ok',
            data: buildGraphQueryPayload({
              operation,
              sourceFiles,
              nodes: [],
              affectedFiles: [],
              depthGroups,
              riskLevel: classifyBlastRadiusRisk(depthGroups, ambiguityCandidates),
              minConfidence,
              ambiguityCandidates,
              failureFallback: {
                reason: 'ambiguous_subject',
                code: 'ambiguous_subject',
                partialResult: buildPartialBlastRadiusResult(sourceFiles, [], [], depthGroups),
              } satisfies BlastRadiusFailureFallback,
            }, readiness, 'code_graph_query blast_radius ambiguity payload'),
          }, null, 2),
        }],
      };
    }

    if (sourceFiles.length === 0) {
      const depthGroups = buildDepthGroups([], effectiveDepth);
      return {
        content: [{
          type: 'text',
          text: JSON.stringify({
            status: 'ok',
            data: buildGraphQueryPayload({
              operation,
              sourceFiles,
              nodes: [],
              affectedFiles: [],
              depthGroups,
              riskLevel: classifyBlastRadiusRisk(depthGroups, []),
